import{_ as e,o as i,c as t,a}from"./app.175b6bd1.js";var n="/aktivitaeten/BDM-2026-06/00_06-2026.jpg",r="/aktivitaeten/BDM-2026-06/01_06-2026.jpg",s="/aktivitaeten/BDM-2026-06/02_06-2026.jpg",d="/aktivitaeten/BDM-2026-06/03_06-2026.jpg",l="/aktivitaeten/BDM-2026-06/04_06-2026.jpg",m="/aktivitaeten/BDM-2026-06/05_06-2026.jpg",g="/aktivitaeten/BDM-2026-06/06_06-2026.jpg",o="/aktivitaeten/BDM-2026-06/07_06-2026.jpg",p="/aktivitaeten/BDM-2026-06/08_06-2026.jpg",c="/aktivitaeten/BDM-2026-06/09_06-2026.jpg",u="/aktivitaeten/BDM-2026-06/10_06-2026.jpg",h="/aktivitaeten/BDM-2026-06/11_06-2026.jpg",_="/aktivitaeten/BDM-2026-06/12_06-2026.jpg",k="/aktivitaeten/BDM-2026-06/13_06-2026.jpg",v="/aktivitaeten/BDM-2026-06/14_06-2026.jpg",B="/aktivitaeten/BDM-2026-06/15_06-2026.jpg",M="/aktivitaeten/BDM-2026-06/16_06-2026.jpg",D="/aktivitaeten/BDM-2026-06/17_06-2026.jpg",b="/aktivitaeten/BDM-2026-06/18_06-2026.jpg",f="/aktivitaeten/BDM-2026-06/19_06-2026.jpg",w="/aktivitaeten/BDM-2026-06/20_06-2026.jpg",j="/aktivitaeten/BDM-2026-06/21_06-2026.jpg",A="/aktivitaeten/BDM-2026-06/22_06-2026.jpg",S="/aktivitaeten/BDM-2026-06/23_06-2026.jpg",E="/aktivitaeten/BDM-2026-06/24_06-2026.jpg",z="/aktivitaeten/BDM-2026-06/25_06-2026.jpg",O="/aktivitaeten/BDM-2026-06/26_06-2026.jpg",P="/aktivitaeten/BDM-2026-06/27_06-2026.jpg",T="/aktivitaeten/BDM-2026-06/28_06-2026.jpg",W="/aktivitaeten/BDM-2026-06/29_06-2026.jpg",L="/aktivitaeten/BDM-2026-06/30_06-2026.jpg",H="/aktivitaeten/BDM-2026-06/31_06-2026.jpg",G="/aktivitaeten/BDM-2026-06/32_06-2026.jpg",R="/aktivitaeten/BDM-2026-06/33_06-2026.jpg",C="/aktivitaeten/BDM-2026-06/34_06-2026.jpg",I="/aktivitaeten/BDM-2026-06/35_06-2026.jpg",Q="/aktivitaeten/BDM-2026-06/36_06-2026.jpg",F="/aktivitaeten/BDM-2026-06/37_06-2026.jpg",K="/aktivitaeten/BDM-2026-06/38_06-2026.jpg",q="/aktivitaeten/BDM-2026-06/39_06-2026.jpg",N="/aktivitaeten/BDM-2026-06/40_06-2026.jpg",V="/aktivitaeten/BDM-2026-06/41_06-2026.jpg",x="/aktivitaeten/BDM-2026-06/42_06-2026.jpg",U="/aktivitaeten/BDM-2026-06/43_06-2026.jpg",X="/aktivitaeten/BDM-2026-06/44_06-2026.jpg",J="/aktivitaeten/BDM-2026-06/45_06-2026.jpg",y="/aktivitaeten/BDM-2026-06/46_06-2026.jpg",Z="/aktivitaeten/BDM-2026-06/47_06-2026.jpg",Y="/aktivitaeten/BDM-2026-06/48_06-2026.jpg",$="/aktivitaeten/BDM-2026-06/49_06-2026.jpg",ee="/aktivitaeten/BDM-2026-06/50_06-2026.jpg",ie="/aktivitaeten/BDM-2026-06/51_06-2026.jpg",te="/aktivitaeten/BDM-2026-06/52_06-2026.jpg";const ae={},ne=a('<h1 id="bilder-des-monats-juni-2026" tabindex="-1"><a class="header-anchor" href="#bilder-des-monats-juni-2026" aria-hidden="true">#</a> Bilder des Monats Juni 2026</h1><p>Eine tolle Aktivierung der POTA Parks DE-0661 &amp; DE-0662 im Burgweiler Ried bei Ostrach. 45 QSOs inkl. einer Verbindung in die USA kamen ins Log. Kleiner Wermutstropfen sind die M\xFCckenstiche an den Armen und im Gesicht in ungef\xE4hr der gleichen Anzahl wie die QSOs. Verwendet hab ich meinen alten IC-706MKIIG und die MC-750. https://de.wikipedia.org/wiki/Pfrunger-Burgweiler_Ried</p><p><img src="'+n+'" alt="Bilder des Monats"></p><p>OE/DB8KN auf dem Kirchberg (OE/TI-545). Heute habe ich, Niels, zum ersten mal einen Gipfel in CW aktiviert. Gleichzeitig waren die 5 QSOs meine allerersten CW QSOs \xFCberhaupt. Sie wahren dementsprechend noch recht holprig und unsauber, meine Motivation weiter zu lernen und besser zu werden ist durch die Gipfeltour aber umso gr\xF6\xDFer geworden.</p><p><img src="'+r+'" alt="Bilder des Monats"><img src="'+s+'" alt="Bilder des Monats"></p><p>DL3BOB am Holzm\xFChleweiher bei Immenried (JN47WU) Heute konnte ich DE-0940 und DE-0963 aktivieren. Der Spot bot angenehmen Schatten und \xFCber den Weiher wehte ein klein wenig Wind. Ich konnte 38 QSOs ins Log bekommen. Dabei waren auch wieder 2 QSOs in die USA</p><p><img src="'+d+'" alt="Bilder des Monats"></p><p>DB7GKA am 19.06.2026 bei der sp\xE4tnachmittaglichen Aktivierung (10 QSO in CW) im Landschaftspark Hachinger Tal DE-0546 bei JN58TB46.</p><p>Der Spot befindet sich auf einer Anh\xF6he im Park und bietet viel Platz f\xFCr den Aufbau einer Drahtantenne. Die Sitzbank befindet sich ab der Mittagszeit bis Abends im Schatten und bietet einen sch\xF6nen Ausblick auf die im Park befindliche ehemalige Landebahn.</p><p><img src="'+l+'" alt="Bilder des Monats"><img src="'+m+'" alt="Bilder des Monats"><img src="'+g+'" alt="Bilder des Monats"><img src="'+o+'" alt="Bilder des Monats"></p><p>Bei sommerlich warmen Temperaturen hat DL9CE am 21.06.2026 den Aawiesenpark DE-0873 in Herford aktiviert. Hier fiel schnell die Wahl auf einen Platz im Schatten, mangels Aufbaum\xF6glichkeit f\xFCr die Vertikalantenne kam die Endfed mit 20m Draht zum Einsatz, als Inverted V durch einen Baum gespannt. Trotz teils schwieriger Bandbedingungen auf 40m kamen am Ende 34 QSOs (SSB + FT8) ins Log und die Aktivierung war gegl\xFCckt.</p><p><img src="'+p+'" alt="Bilder des Monats"><img src="'+c+'" alt="Bilder des Monats"></p><p>CB-Handfunkerei - einmal anders</p><p>Es ging auf den Sch\xFCberg in Ammersbek mit einer kleinen, kompakten Ausr\xFCstung.</p><p>Setup: President Randy 3+ mit der Draussenfunk-Vertikal Antenne, auf einem kleinen, niedrigen Lichtstativ aufgestellt.</p><p>Holger, 13-OT-4242, Die Erdbeere.</p><p><img src="'+u+'" alt="Bilder des Monats"><img src="'+h+'" alt="Bilder des Monats"><img src="'+_+'" alt="Bilder des Monats"><img src="'+k+'" alt="Bilder des Monats"></p><p><img src="'+v+'" alt="Bilder des Monats"></p><p>DL7DL, 40m, QRP, FT8, 21QSOs Der Landschaftspark Degenershausen wurde vor 2 Jahren als DE-0736 angelegt und niemand hatte bis heute den Park im Naturpark Harz DE-0065 aktiviert. Highlight in FT8/6W ein QSO mit HI8DX in der Dominikanischen Republik (~8.000 km). Als Antenne, eine HF-P1 mit Verl\xE4ngerungsspule und einem 5m Strahler.</p><p><img src="'+B+'" alt="Bilder des Monats"><img src="'+M+'" alt="Bilder des Monats"><img src="'+D+'" alt="Bilder des Monats"><img src="'+b+'" alt="Bilder des Monats"><img src="'+f+'" alt="Bilder des Monats"><img src="'+w+'" alt="Bilder des Monats"></p><p>DL2XT im Park DE-0297. Ich habe das 20m Band in SSB gearbeitet mit 20 Watt von dem Xiegu G90. Antenne war die Draussenfunker Groundplane. Gesamt sind 27 QSOs in den Kasten gekommen. Von Spanien, Schweden bis Kanada, Amerika und Zypern war alles dabei. Einige Park-to-Park QSOs haben auch geklappt.</p><p><img src="'+j+'" alt="Bilder des Monats"><img src="'+A+'" alt="Bilder des Monats"><img src="'+S+'" alt="Bilder des Monats"><img src="'+E+'" alt="Bilder des Monats"></p><p>Draussenfunker Tiere Treffen 2026</p><p><img src="'+z+'" alt="Bilder des Monats"><img src="'+O+'" alt="Bilder des Monats"></p><p>DL7LW in DE-1183 und DE-0712, CW</p><p>Diese Woche ergab sich f\xFCr mich die M\xF6glichkeit mal wieder eine Runde drau\xDFen zu funken und von vornherein stand fest - das wird meine erste Aktivierung nur in CW. Das Mike ist zur Sicherheit gleich zu Hause geblieben, das Diktierger\xE4t hab ich beiseite gelegt. Also ohne Netz und doppelten Boden. Gefunden habe ich hierf\xFCr eine ruhige Ecke in einem sch\xF6nen Leipziger Park. Mit einer ausladenden Eiche f\xFCr ausreichend Schatten sowie genug M\xF6glichkeiten f\xFCr meine xOTA-EFHW. Als TRX hatte ein KX3 seine Premiere bei mir. Den hatte ich das Gl\xFCck die Tage in die H\xE4nde zu bekommen, also kam der auch gleich mit.</p><p>Und wie lief es? Genau so wie man sich das bei ersten mal so vorstellt. Einiges klappte ganz gut, Anderes nicht so. Und ich habe viele Fehler gemacht. Habe Callsigns nicht erkannt, musste x-mal nachfragen. Mitschreiben auf Papier (brauche ich noch) plus loggen in Ham2K (brauche ich auf jeden Fall) war ziemlich holprig. Teilweise waren ganze Buchstaben aus dem Kopf verschwunden. Aber das alles war irgendwie \xFCberhaupt gar kein Problem. Dank vieler grandioser OPs da drau\xDFen, die auch nach der x-ten Nachfrage nach Ihrem Callsign Geduld mit mir hatten.</p><p>In Summe lief es aber ganz gut. Die Aktivierung war erfolgreich, 16 CW-QSOs sind im Log. Dazu hat es eine Menge Spa\xDF gemacht und war am Ende auch gar nicht so schlimm. F\xFCr mich eine sch\xF6ne und denkw\xFCrdige Aktivierung. Und, es wird mehr davon geben!</p><p>Felix, DL7LW</p><p><img src="'+P+'" alt="Bilder des Monats"><img src="'+T+'" alt="Bilder des Monats"><img src="'+W+'" alt="Bilder des Monats"><img src="'+L+'" alt="Bilder des Monats"><img src="'+H+'" alt="Bilder des Monats"><img src="'+G+'" alt="Bilder des Monats"></p><p>Mr. POTA in Deutschland und Polen unterwegs. Die Bilder sind in Polen und Deutschland entstanden.</p><p>Das Manpack und der Kurzwellen TRX sind aus dem 3D Drucker.</p><p><img src="'+R+'" alt="Bilder des Monats"><img src="'+C+'" alt="Bilder des Monats"><img src="'+I+'" alt="Bilder des Monats"><img src="'+Q+'" alt="Bilder des Monats"><img src="'+F+'" alt="Bilder des Monats"><img src="'+K+'" alt="Bilder des Monats"><img src="'+q+'" alt="Bilder des Monats"><img src="'+N+'" alt="Bilder des Monats"><img src="'+V+'" alt="Bilder des Monats"><img src="'+x+'" alt="Bilder des Monats"></p><p>Heute hie\xDF f\xFCr DF6TG endlich wieder &quot; Draussenfunken&quot; Eigentlich wollte ich nur bis zur H\xFCtte hoch,und dann aufbauen. Im Rucksack war der Xiegu 6100,Eremit 6ah,Pac12 Antenne und das Anytone D168UV sowie Meshcore. Aber.......dann l\xE4chelte mich gegen\xFCber Gipfel an,und sagte&quot;Thomas komm doch schnell hoch&quot; Also ging es weiter,bis ich schlie\xDFlich oben war. Zwar nur 1500 Meter hoch,aber besser als nichts Ich kenne den Gipfel gut,immer wieder sch\xF6n dort,mit Rundumblick, und wenige,die dort hingehen. Einziger Knackpunkt ist der Felsenkamin den man hoch muss, aber was tut man denn nicht alles um &quot; Draussenfunker&quot; sein zu d\xFCrfen Oben alles aufgebaut, und auf 20m gedreht. Da ja wieder WWA Contest ist,sind die B\xE4nder wieder sehr gut frequentiert. Es ging mit 10 Watt PEP nach DL mit SOTA Referenz, ON,CS,YL,DL,OE und HB. Auch Meshcore war mit im Rucksack, und auch dort gingen der Reihe nach eine nach der anderen Meldung ein Leider musste ich abbauen, da mir das Wetter im Nacken sa\xDF. Also schnell aber bedacht und konzentriert den Felsenkamin wieder runter,der Rest war dann Routine. Was nat\xFCrlich IMMER dazugeh\xF6rt, ist die wohl verdiente Einkehr auf einer Alpe Auf dem Wec zum Auto wurde es dann rundrum schwarz,und es begann dann mit Regen und schweren Gewittern. Alles richtig gemacht Wieder einmal hat es sich heute best\xE4tigt, Draussenfunken ist einfach nur 73,aus dem Allg\xE4u Thomas, DF6TG &quot;Der von der Seilbahn&quot; Oder wie es auch noch auf der HAM hie\xDF &quot; Der Mann aus den Bergen&quot;</p><p><img src="'+U+'" alt="Bilder des Monats"><img src="'+X+'" alt="Bilder des Monats"><img src="'+J+'" alt="Bilder des Monats"><img src="'+y+'" alt="Bilder des Monats"><img src="'+Z+'" alt="Bilder des Monats"><img src="'+Y+'" alt="Bilder des Monats"><img src="'+$+'" alt="Bilder des Monats"><img src="'+ee+'" alt="Bilder des Monats"><img src="'+ie+'" alt="Bilder des Monats"><img src="'+te+'" alt="Bilder des Monats"></p>',35),re=[ne];function se(de,le){return i(),t("div",null,re)}var ge=e(ae,[["render",se],["__file","2026-06-30-Bilder-Des-Monats-Juni.html.vue"]]);export{ge as default};
